// Token info endpoint - shows decoded token details (protected)
app.get('/auth/tokeninfo', isAuthenticated, (req, res) => {
  const idToken = req.session.tokens.idToken;

  // Decode the stored id_token again for display
  const decoded = jwt.decode(idToken, { complete: true });

  res.json({
    warning: 'This token was decoded using jwt.decode() without signature verification',
    header: decoded.header,
    payload: decoded.payload,
    tokenPresent: {
      accessToken: !!req.session.tokens.accessToken,
      refreshToken: !!req.session.tokens.refreshToken,
      idToken: !!req.session.tokens.idToken,
    },
  });
});

// Logout endpoint
app.get('/auth/logout', (req, res) => {
  const user = req.session.user;

  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
      return res.status(500).json({ error: 'Failed to logout' });
    }

    console.log(`User logged out: ${user ? user.email : 'unknown'}`);

    res.clearCookie('connect.sid');
    res.json({
      message: 'Successfully logged out',
      loginUrl: '/auth/login',
    });
  });
});

// Session status endpoint
app.get('/auth/status', (req, res) => {
  if (req.session && req.session.user) {
    const tokenAge = Date.now() - req.session.tokens.issuedAt;
    const tokenMaxAge = req.session.tokens.expiresIn * 1000;
    const tokenExpired = tokenAge > tokenMaxAge;

    res.json({
      authenticated: true,
      user: {
        sub: req.session.user.sub,
        email: req.session.user.email,
        name: req.session.user.name,
      },
      session: {
        authTime: new Date(req.session.authTime).toISOString(),
        tokenExpired: tokenExpired,
        tokenAgeSeconds: Math.floor(tokenAge / 1000),
      },
    });
  } else {
    res.json({
      authenticated: false,
      loginUrl: '/auth/login',
    });
  }
});

// Refresh token endpoint (protected)
app.post('/auth/refresh', isAuthenticated, async (req, res) => {
  try {
    const refreshToken = req.session.tokens.refreshToken;

    if (!refreshToken) {
      return res.status(400).json({ error: 'No refresh token available' });
    }

    const response = await axios.post(OIDC_CONFIG.tokenEndpoint, new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OIDC_CONFIG.clientId,
      client_secret: OIDC_CONFIG.clientSecret,
    }).toString(), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    });

    const newTokens = response.data;

    // Update session tokens
    req.session.tokens.accessToken = newTokens.access_token;
    req.session.tokens.expiresIn = newTokens.expires_in;
    req.session.tokens.issuedAt = Date.now();

    if (newTokens.refresh_token) {
      req.session.tokens.refreshToken = newTokens.refresh_token;
    }

    if (newTokens.id_token) {
      req.session.tokens.idToken = newTokens.id_token;

      // Decode the new id_token and update user claims
      const { payload: newClaims } = decodeIdToken(newTokens.id_token);
      req.session.user = {
        sub: newClaims.sub,
        email: newClaims.email,
        emailVerified: newClaims.emailVerified,
        name: newClaims.name,
        givenName: newClaims.givenName,
        familyName: newClaims.familyName,
        picture: newClaims.picture,
      };
    }

    console.log(`Tokens refreshed for user: ${req.session.user.email}`);

    res.json({
      message: 'Tokens refreshed successfully',
      expiresIn: newTokens.expires_in,
    });

  } catch (error) {
    console.error('Token refresh error:', error.response ? error.response.data : error.message);
    res.status(500).json({ error: 'Failed to refresh tokens' });
  }
});

